patch:
Don't try to access not-present CPUs. 
Conservative governor will always oops on SMP without this fix.

Signed-off-by: Venkatesh Pallipadi <venkatesh.pallipadi@intel.com>

Index: linux-2.6.12/drivers/cpufreq/cpufreq_conservative.c
===================================================================
--- linux-2.6.12.orig/drivers/cpufreq/cpufreq_conservative.c	2005-06-17 12:48:29.000000000 -0700
+++ linux-2.6.12/drivers/cpufreq/cpufreq_conservative.c	2005-09-22 15:26:54.669850424 -0700
@@ -315,9 +315,9 @@
 	policy = this_dbs_info->cur_policy;

 	if ( init_flag == 0 ) {
-		for ( /* NULL */; init_flag < NR_CPUS; init_flag++ ) {
-			dbs_info = &per_cpu(cpu_dbs_info, init_flag);
-			requested_freq[cpu] = dbs_info->cur_policy->cur;
+		for_each_online_cpu(j) {
+			dbs_info = &per_cpu(cpu_dbs_info, j);
+			requested_freq[j] = dbs_info->cur_policy->cur;
 		}
 		init_flag = 1;
 	}
